import React from 'react';

function App() {
  // Styles
  const navStyle = {
    display: 'flex',
    justifyContent: 'center', // center menu items
    alignItems: 'center',
    position: 'sticky', // sticky top
    top: 0,
    backgroundColor: '#333',
    padding: '15px 0',
    zIndex: 1000
  };

  const linkStyle = {
    margin: '0 20px',
    color: '#fff',
    textDecoration: 'none',
    fontWeight: 'bold',
    fontSize: '18px',
    transition: 'color 0.3s'
  };

  const linkHoverStyle = {
    color: '#ff6347' // tomato color on hover
  };

  const sectionStyle = {
    padding: '100px 20px',
    textAlign: 'center'
  };

  const sectionAltStyle = {
    padding: '100px 20px',
    textAlign: 'center',
    backgroundColor: '#f0f0f0'
  };

  const buttonStyle = {
    padding: '10px 25px',
    fontSize: '16px',
    cursor: 'pointer',
    marginTop: '20px'
  };

  // Hover effect handler
  const handleMouseEnter = e => e.target.style.color = linkHoverStyle.color;
  const handleMouseLeave = e => e.target.style.color = linkStyle.color;

  return (
    <div>
      {/* Navigation Menu */}
      <nav style={navStyle}>
        <a
          href="#home"
          style={linkStyle}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >Home</a>
        <a
          href="#about"
          style={linkStyle}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >About</a>
        <a
          href="#contact"
          style={linkStyle}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >Contact</a>
      </nav>

      {/* Home Section */}
      <section id="home" style={sectionStyle}>
        <h1>Hello, Tayyab!</h1>
        <p>My first React app is running!</p>
        <button style={buttonStyle} onClick={() => alert('You clicked me!')}>Click Me</button>
      </section>

      {/* About Section */}
      <section id="about" style={sectionAltStyle}>
        <h1>About Section</h1>
        <p>This is a modern React navigation example with a centered menu.</p>
      </section>

      {/* Contact Section */}
      <section id="contact" style={sectionStyle}>
        <h1>Contact Section</h1>
        <p>Get in touch!</p>
      </section>
    </div>
  );
}

export default App;
